oxy_webhelp_navlinks = {"tocId-d30753e20853":{"topics":[{"title":"Prerequisites for Azure SQL MI Rubrik backup","shortdesc":"<p class=\"shortdesc\">Enabling Rubrik backups of Azure SQL Managed Instances requires specific         configuration on both <span class=\"ph\">RSC<\/span> and Azure.<\/p>","href":"saas\/azr_sql_mi_prereq_rbk_backup.html","attributes":{"data-id":"azr_sql_mi_prereq_rbk_backup"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_prereq_rbk_backup-d30753e20854","topics":[]},{"title":"SQL Server permissions for Azure SQL MI Rubrik backups","shortdesc":"<p class=\"shortdesc\">Information about the minimal set of permissions that <span class=\"ph\">RSC<\/span> uses during         backup, combined with the SQL Server objects it creates on the source Azure SQL Managed         Instance during setup, ensuring secure and isolated operations.<\/p>","href":"saas\/azr_sql_mi_rbk_backup_sql_permissions.html","attributes":{"data-id":"azr_sql_mi_rbk_backup_sql_permissions"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_rbk_backup_sql_permissions-d30753e20868","topics":[]},{"title":"Network configurations for Azure SQL MI","shortdesc":"<p class=\"shortdesc\">To back up an Azure SQL Managed Instance, you must configure a secure connection         between the Rubrik Exocompute instance and the source MI. <span class=\"ph\">RSC<\/span> recommends a         private endpoint for security. Note that private endpoints incur Azure costs. A VNet peering         is a supported, lower-cost alternative.<\/p>","href":"saas\/azr_sql_mi_nw_configs.html","attributes":{"data-id":"azr_sql_mi_nw_configs"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_nw_configs-d30753e20882","next":"azr_sql_mi_nw_configs-d30753e20882"},{"title":"Credential management for Azure SQL MI Rubrik backups","shortdesc":"<p class=\"shortdesc\">Credential management for taking Rubrik backups of Azure SQL Managed Instance         involves creating database login credentials with the permissions required for the backup         workflow.<\/p>","href":"saas\/azr_sql_mi_cred_mgmt_rbk_backup.html","attributes":{"data-id":"azr_sql_mi_cred_mgmt_rbk_backup"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_cred_mgmt_rbk_backup-d30753e20925","next":"azr_sql_mi_cred_mgmt_rbk_backup-d30753e20925"}]}};